function preflightInit(cwd: string, options: { skipPreflight: boolean }) {
	const sveltePkg = getDependencyPackageInfo(cwd, "svelte")?.pkg;
	const tailwindPkg = getDependencyPackageInfo(cwd, "tailwindcss")?.pkg;

	const pkg = project.getPackageInfo(cwd);
	const deps = { ...pkg.dependencies, ...pkg.devDependencies };

	const svelte = sveltePkg?.version ?? deps["svelte"];
	const tailwindcss = tailwindPkg?.version ?? deps["tailwindcss"];

	const result = checkInitDependencies({ svelte, tailwindcss });
	if (result.ok) return;

	if (!options.skipPreflight) throw result.error;

	p.note(
		`${color.red(result.error.message)}\nContinuing initialization with ${color.bold("--skip-preflight")}.`
	);
}

async function processFile(
  file,
  stylesDir,
  distDir,
  defaultTheme,
  theme,
  responsive,
  exclude,
  layer,
) {
  const styleContent = await fs.readFile(path.join(stylesDir, `${distDir}/${file}.css`), "utf-8")
  let stylesContent = await compileAndExtractStyles(styleContent, defaultTheme, theme)

  if (responsive && !exclude.includes(file)) {
    stylesContent = await generateResponsiveVariants(stylesContent)
  }

  stylesContent = cleanCss(stylesContent)

  if (layer) {
    stylesContent = `@layer ${layer} {\n${stylesContent}\n}`
  }

  await fs.writeFile(
    path.join(import.meta.dirname, distDir, `${distDir}/${file}.css`),
    stylesContent,
  )
}

async function generateMetadata(props: Props): Promise<Metadata> {
  let params = await props.params;
  let sectionAndTitle = await getSectionAndTitleBySlug(params.slug);
  let post = await getDocPageBySlug(params.slug);

  if (!post) {
    return notFound();
  }

  let title = `${post.title} - ${sectionAndTitle?.section ?? ""}`;

  return {
    metadataBase: new URL("https://tailwindcss.com"),
    title,
    description: post.description,
    openGraph: {
      title,
      description: post.description,
      type: "article",
      url: `/docs/${params.slug}`,
      images: [{ url: `/api/og?path=/docs/${params.slug}` }],
    },
    twitter: {
      card: "summary_large_image",
      title,
      description: post.description,
      images: [{ url: `/api/og?path=/docs/${params.slug}` }],
      site: "@tailwindcss",
      creator: "@tailwindcss",
    },
  };
}

async function generateMetadata(props: Props): Promise<Metadata> {
  let parts = (await props.params).slug;
  if (!parts) return notFound();

  let [slug] = parts.filter((part) => part.trim() !== "");

  let guide = await loadGuide(slug);
  if (!guide) return notFound();

  let { page } = guide;

  return {
    metadataBase: new URL("https://tailwindcss.com"),
    title: page.title,
    description: page.description,
    openGraph: {
      title: page.title,
      description: page.description,
      type: "article",
      url: `/docs/${guide.slug}`,
      images: [{ url: `/api/og?path=/docs/${guide.slug}` }],
    },
    twitter: {
      card: "summary_large_image",
      title: page.title,
      description: page.description,
      images: [{ url: `/api/og?path=/docs/${guide.slug}` }],
      site: "@tailwindcss",
      creator: "@tailwindcss",
    },
  };
}

